#!/bin/bash
set -ex

# --- Fetch inputs (no-op if already present) ---
wget -nc https://pism-cloud-data.s3.amazonaws.com/inverse/grid_RGI2000-v7.0-C-01-04374.nc
wget -nc https://pism-cloud-data.s3.amazonaws.com/inverse/bootfile_maffezzoli_RGI2000-v7.0-C-01-04374.nc
wget -nc https://pism-cloud-data.s3.amazonaws.com/inverse/obs_RGI2000-v7.0-C-01-04374.nc
wget -nc https://pism-cloud-data.s3.amazonaws.com/inverse/era5_wgs84_RGI2000-v7.0-C-01-04374.nc

# --- Ensure output directory exists ---
mkdir -p isoglen_maffezzoli inv_isoglen_maffezzoli forward_inv_isoglen_maffezzoli

# --- Forward simulation to produce initial state ---
mpirun -np 8 pism -stress_balance.model ssa+sia -stress_balance.ssa.method fd -stress_balance.sia.flow_law isothermal_glen -stress_balance.sia.surface_gradient_method eta -stress_balance.ssa.flow_law isothermal_glen -hydrology.model null -hydrology.null_diffuse_till_water no -atmosphere.given.file era5_wgs84_RGI2000-v7.0-C-01-04374.nc -atmosphere.models given -basal_resistance.pseudo_plastic.enabled yes -basal_resistance.pseudo_plastic.q 0.75 -basal_resistance.pseudo_plastic.u_threshold 100m/yr -basal_yield_stress.model mohr_coulomb -basal_yield_stress.mohr_coulomb.till_effective_fraction_overburden 0.025 -basal_yield_stress.mohr_coulomb.till_phi_default 35 -calving.methods float_kill -energy.model none -geometry.front_retreat.use_cfl yes -geometry.part_grid.enabled yes -geometry.remove_icebergs yes -grid.Lbz 0 -grid.Lz 1200 -grid.Mbz 1 -grid.Mz 61 -grid.dx 500m -grid.dy 500m -grid.file grid_RGI2000-v7.0-C-01-04374.nc -stress_balance.sia.bed_smoother.range 1000 -grid.registration center -input.bootstrap yes -input.file bootfile_maffezzoli_RGI2000-v7.0-C-01-04374.nc -input.forcing.buffer_size 390 -input.forcing.time_extrapolation yes -surface.force_to_thickness.file bootfile_maffezzoli_RGI2000-v7.0-C-01-04374.nc -surface.force_to_thickness.alpha 0.5 -surface.force_to_thickness.ice_free_alpha_factor 10 -surface.models pdd,forcing -time.calendar standard -time.end 1985-01-01 -time.reference_date 1980-01-01 -time.start 1980-01-01 -time_stepping.skip.enabled yes -time_stepping.skip.max 100 -output.file isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01.nc -output.spatial.file isoglen_maffezzoli/spatial_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01.nc -output.spatial.vars velsurf_mag,velbase_mag,usurf,thk,velsurf,hardav,bwp,bwat -output.spatial.times yearly -output.size medium -output.sizes.medium sftgif,velsurf_mag,mask,usurf,velbase_mag,velsurf,hardav,velsurf -output.spatial.stop_missing no

# --- Post-process: produce the inversion-friendly file ---
cdo -O setmisstoc,0 isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01.nc isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01_0.nc
ncks -A -v pism_config isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01.nc isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01_0.nc


# --- Post-process: adjust misfit_weight ---
python add_latlon.py isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01.nc isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01_latlon.nc
python add_latlon.py obs_RGI2000-v7.0-C-01-04374.nc obs_RGI2000-v7.0-C-01-04374_latlon.nc
cdo remapycon,isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01_latlon.nc obs_RGI2000-v7.0-C-01-04374_latlon.nc obs_RGI2000-v7.0-C-01-04374_0.nc
ncks -A -v velbase_mag isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01.nc obs_RGI2000-v7.0-C-01-04374_0.nc
ncap2 -O -s "vel_misfit_weight=float(vel_misfit_weight); where(velbase_mag > 1000.0) vel_misfit_weight=0.1" obs_RGI2000-v7.0-C-01-04374_0.nc obs_RGI2000-v7.0-C-01-04374_0.nc

# --- Run Inversion ---
mpirun -np 8 pismi -i isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01_0.nc -inv_data obs_RGI2000-v7.0-C-01-04374_0.nc -o inv_isoglen_maffezzoli/inv_obs_hybrid_it_250_meansquare_p_10_h1_1_l2_0_ls_1e2_vs_100_hubers_1e2.nc -options_left  -inv_design tauc -inverse.stress_balance.velocity_scale 100 -inverse.stress_balance.length_scale 1e2 -inverse.design.cH1 1 -inverse.design.cL2 0 -inverse.max_iterations 250 -inverse.design.param exp -inverse.stress_balance.method tikhonov_blmvm  -inverse.stress_balance.tauc_min 1e4 -inverse.stress_balance.tauc_max 5e7 -inverse.tikhonov.penalty_weight 10 -inverse.use_zeta_fixed_mask yes -inverse.adjoint.method exact -inv_grounded_ice_tauc -inverse.state_func meansquare -inverse.huber.delta 1e2 -basal_resistance.pseudo_plastic.enabled yes -basal_resistance.pseudo_plastic.q 0.75 -basal_resistance.pseudo_plastic.u_threshold 100m/yr -basal_yield_stress.model mohr_coulomb -basal_yield_stress.mohr_coulomb.till_effective_fraction_overburden 0.025 -basal_yield_stress.mohr_coulomb.till_phi_default 40 -hydrology.model null -hydrology.null_diffuse_till_water  -energy.model none -stress_balance.model ssa+sia -stress_balance.ssa.method fem -stress_balance.sia.flow_law gpbld -stress_balance.sia.surface_gradient_method eta -stress_balance.ssa.flow_law isothermal_glen -stress_balance.ssa.dirichlet_bc  -remove_sia -inverse.tikhonov.atol 3e-4


# --- Forward run with inverted tauc ---
mpirun -np 8 pism -stress_balance.model ssa+sia -stress_balance.ssa.method fem -stress_balance.sia.flow_law isothermal_glen -stress_balance.sia.max_diffusivity 100000.0 -stress_balance.sia.surface_gradient_method eta -stress_balance.ssa.flow_law isothermal_glen -basal_resistance.pseudo_plastic.enabled yes -basal_resistance.pseudo_plastic.q 0.75 -basal_resistance.pseudo_plastic.u_threshold 100m/yr -basal_yield_stress.model constant -hydrology.model null -hydrology.null_diffuse_till_water no -energy.model none -geometry.front_retreat.use_cfl yes -geometry.part_grid.enabled yes -geometry.remove_icebergs yes -calving.methods float_kill -grid.Lbz 0 -grid.Lz 1200 -grid.Mbz 1 -grid.Mz 61 -grid.dx 500m -grid.dy 500m -grid.file grid_RGI2000-v7.0-C-01-04374.nc -stress_balance.sia.bed_smoother.range 1000 -grid.registration center -time.calendar standard -time.start 1980-01-01 -time.reference_date 1980-01-01 -y 0.0001 -time_stepping.skip.enabled yes -time_stepping.skip.max 100 -atmosphere.given.file era5_wgs84_RGI2000-v7.0-C-01-04374.nc -atmosphere.models given -surface.force_to_thickness.file bootfile_maffezzoli_RGI2000-v7.0-C-01-04374.nc -surface.force_to_thickness.alpha 0.99 -surface.force_to_thickness.ice_free_alpha_factor 10 -surface.models pdd,forcing -input.forcing.buffer_size 390 -input.forcing.time_extrapolation yes -i isoglen_maffezzoli/state_hybrid_maffezzoli_null_g500m_RGI2000-v7.0-C-01-04374_id_0_1980-01-01_1985-01-01_0.nc -input.regrid.file inv_isoglen_maffezzoli/inv_obs_hybrid_it_250_meansquare_p_10_h1_1_l2_0_ls_1e2_vs_100_hubers_1e2.nc -input.regrid.vars tauc -output.file forward_inv_isoglen_maffezzoli/state_fwd_hybrid_g500m_RGI2000-v7.0-C-01-04374.nc -output.spatial.file forward_inv_isoglen_maffezzoli/spatial_fwd_hybrid_g500m_RGI2000-v7.0-C-01-04374.nc -output.spatial.vars velsurf_mag,velbase_mag,usurf,thk,velsurf,hardav,tauc,mask -output.spatial.times yearly -output.size medium
